refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/coins_gray.jpg"));
mask = imcomplement(imbinarize(image, "otsu"));
mask = imbwareaopen(mask, 80);

foregroundPixels = imcountnonzero(mask);
totalPixels = size(mask, 1) * size(mask, 2);
foregroundPercent = 100 * foregroundPixels / totalPixels;

mprintf("foreground pixels : %d\n", foregroundPixels);
mprintf("foreground percent: %.2f%%\n", foregroundPercent);

subplot(1, 2, 1);
imshow(image);
title("Input");
subplot(1, 2, 2);
imshow(mask);
title("Counted foreground");

rgb = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
channelCounts = imcountnonzero(rgb > 120);
disp(channelCounts);
